import{_ as s,o as e,c as t,ag as i}from"./chunks/framework.B9unkguw.js";const c=JSON.parse('{"title":"다운로드 및 설치","description":"","frontmatter":{},"headers":[],"relativePath":"ko/qgc-user-guide/getting_started/download_and_install.md","filePath":"ko/qgc-user-guide/getting_started/download_and_install.md"}'),o={name:"ko/qgc-user-guide/getting_started/download_and_install.md"};function l(n,a,r,p,d,h){return e(),t("div",null,a[0]||(a[0]=[i(`<h1 id="다운로드-및-설치" tabindex="-1">다운로드 및 설치 <a class="header-anchor" href="#다운로드-및-설치" aria-label="Permalink to &quot;다운로드 및 설치&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>These are <strong>daily build</strong> download links with the latest features. If you are looking for the last stable release, see the <a href="https://docs.qgroundcontrol.com/Stable_V5.0/en/qgc-user-guide/getting_started/download_and_install.html" target="_blank" rel="noreferrer">stable docs</a>.</p></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>설치 후 QGroundControl이 정상적으로 실행되지 않으면, <a href="./../troubleshooting/qgc_setup.html">QGC 설정 문제 해결</a>편을 참고하여 문제를 해결할 수 있습니다.</p></div><h2 id="시스템-요구-사항" tabindex="-1">시스템 요구 사항 <a class="header-anchor" href="#시스템-요구-사항" aria-label="Permalink to &quot;시스템 요구 사항&quot;">​</a></h2><p>QGroundControl는 최신 컴퓨터나 모바일 장치에서 실행 가능합니다. 시스템 환경과 사용 가능한 시스템 리소스 상태에 따라 성능이 차이가 날 수 있습니다. More capable hardware will provide a better experience. 최소 8Gb 메모리, SSD 다스크, Nvidia 또는 AMD 그래픽 및 i5 이상의 CPU가 장착된 컴퓨터를 사용하는 것이 좋습니다.</p><p>최신 버전의 운영 체제에서 최적의 사용과 호환성을 발휘할 수 있습니다.</p><h2 id="windows" tabindex="-1">윈도우 <a class="header-anchor" href="#windows" aria-label="Permalink to &quot;윈도우 {#windows}&quot;">​</a></h2><p>Supported versions: Windows 10 (1809 or later), Windows 11:</p><ol><li>Download the installer: <ul><li><a href="https://d176tv9ibo4jno.cloudfront.net/builds/master/QGroundControl-installer-AMD64.exe" target="_blank" rel="noreferrer">x86_64</a></li><li><a href="https://d176tv9ibo4jno.cloudfront.net/builds/master/QGroundControl-installer-ARM64.exe" target="_blank" rel="noreferrer">Arm64</a></li></ul></li><li>다운로드한 설치 파일을 더블 클릭하여 프로그램을 실행합니다.</li></ol><div class="info custom-block"><p class="custom-block-title">INFO</p><p>윈도우용 설치 프로그램은 <strong>QGroundControl</strong>, <strong>GPU 호환 모드</strong> 및 <strong>GPU 안전 모드</strong>의 3가지 바로 가기를 생성합니다. 시작 문제나 비디오 렌더링 문제가 발생하지 않으면, 첫 번째 바로 가기를 사용하십시오. 자세한 내용은 <a href="./../troubleshooting/qgc_setup.html#opengl_troubleshooting">QGroundControl 설정 문제 해결 &gt; 윈도우: UI 렌더링/비디오 드라이버 문제</a>를 참고하십시오.</p></div><h2 id="macOS" tabindex="-1">Mac OS <a class="header-anchor" href="#macOS" aria-label="Permalink to &quot;Mac OS {#macOS}&quot;">​</a></h2><p>Supported versions: macOS 13 (Ventura) or later:</p><ol><li>Download <a href="https://d176tv9ibo4jno.cloudfront.net/builds/master/QGroundControl.dmg" target="_blank" rel="noreferrer">QGroundControl.dmg</a>.</li><li>다운로드한 dmg 파일을 더블 클릭하여 마운트하여, <em>QGroundControl</em> 애플리케이션을 <em>Application</em> 폴더로 드래그합니다.</li></ol><div class="info custom-block"><p class="custom-block-title">INFO</p><p>QGroundControl continues to not be signed. You will not to allow permission for it to install based on your macOS version.</p></div><h2 id="ubuntu" tabindex="-1">우분투 리눅스 <a class="header-anchor" href="#ubuntu" aria-label="Permalink to &quot;우분투 리눅스 {#ubuntu}&quot;">​</a></h2><p>Supported versions: Ubuntu 22.04, 24.04:</p><p>Ubuntu comes with a serial modem manager that interferes with any robotics related use of a serial port (or USB serial). _QGroundControl_을 설치 전에 모뎀 관리자를 제거하고, 직렬 포트 접근 권한을 부여합니다. 동영상 스트리밍을 지원하려면 _GStreamer_을 설치합니다.</p><p><strong>Before installing <em>QGroundControl</em> for the first time:</strong></p><ol><li>Enable serial-port access Add your user to the dialout group so you can talk to USB devices without root:</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo usermod -aG dialout &quot;$(id -un)&quot;</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">INFO</p><p>At login, your shell takes a snapshot of your user and group memberships. Because you just changed groups, you need a fresh login shell to pick up “dialout” access. Logging out and back in reloads that snapshot, so you get the new permissions.</p></div><ol><li>(Optional) Disable ModemManager On some Ubuntu-based systems, ModemManager can claim serial ports that QGC needs. If you don&#39;t use it elsewhere, mask or remove it.</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># preferred: stop and mask the service</span></span>
<span class="line"><span>sudo systemctl mask --now ModemManager.service</span></span>
<span class="line"><span></span></span>
<span class="line"><span># or, if you’d rather remove the package</span></span>
<span class="line"><span>sudo apt remove --purge modemmanager</span></span></code></pre></div><ol><li>On the command prompt, enter:</li></ol><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gstreamer1.0-plugins-bad</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gstreamer1.0-libav</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gstreamer1.0-gl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> python3-gi</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> python3-gst-1.0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libfuse2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libxcb-xinerama0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libxkbcommon-x11-0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libxcb-cursor-dev</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span></span></code></pre></div><p><strong>To install <em>QGroundControl</em>:</strong></p><ol><li><p>Download the AppImage for your architecture:</p><ul><li><a href="https://d176tv9ibo4jno.cloudfront.net/builds/master/QGroundControl-x86_64.AppImage" target="_blank" rel="noreferrer">Linux x86_64</a></li><li><a href="https://d176tv9ibo4jno.cloudfront.net/builds/master/QGroundControl-aarch64.AppImage" target="_blank" rel="noreferrer">Linux aarch64</a></li></ul></li><li><p>Make the AppImage executable</p></li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>chmod +x QGroundControl-&lt;arch&gt;.AppImage</span></span></code></pre></div><ol><li>Run QGroundControl Either double-click the AppImage in your file manager or launch it from a terminal:</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>./QGroundControl-&lt;arch&gt;.AppImage</span></span></code></pre></div><h2 id="android" tabindex="-1">안드로이드 <a class="header-anchor" href="#android" aria-label="Permalink to &quot;안드로이드 {#android}&quot;">​</a></h2><p>Supported versions: Android 9 (API 28) or later (arm 32/64):</p><ul><li><a href="https://d176tv9ibo4jno.cloudfront.net/builds/master/QGroundControl.apk" target="_blank" rel="noreferrer">Android APK</a></li></ul><p>:::important The version of Qt used by QGroundControl requires Android 9 (API 28) as the minimum supported version. It is not possible to support older Android releases. This means that some integrated controllers running older versions of Android are no longer compatible with current builds of QGroundControl. QGroundControl 5.0 stable is the last release that supports these older devices. Note that 5.0 may not fully support firmware versions released after it, so users on older controllers may experience limited compatibility with newer autopilot firmware. :::</p><h2 id="old-stable-releases" tabindex="-1">Old Stable Releases <a class="header-anchor" href="#old-stable-releases" aria-label="Permalink to &quot;Old Stable Releases&quot;">​</a></h2><p>Old stable releases can be found on <a href="https://github.com/mavlink/qgroundcontrol/releases/" target="_blank">GitHub</a>.</p>`,36)]))}const g=s(o,[["render",l]]);export{c as __pageData,g as default};
